sealed class RdpException: kotlin.Exception() {
    
    class ConnectionFailed(
        ) : RdpException() {
        override val message
            get() = ""
    }
    
    class AuthenticationFailed(
        ) : RdpException() {
        override val message
            get() = ""
    }
    
    class ProtocolException(
        ) : RdpException() {
        override val message
            get() = ""
    }
    
    class TlsException(
        ) : RdpException() {
        override val message
            get() = ""
    }
    
    class Disconnected(
        ) : RdpException() {
        override val message
            get() = ""
    }
    
    class IoException(
        ) : RdpException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<RdpException> {
        override fun lift(error_buf: RustBuffer.ByValue): RdpException = FfiConverterTypeRdpError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeRdpError : FfiConverterRustBuffer<RdpException> {
    override fun read(buf: ByteBuffer): RdpException {
        

        return when(buf.getInt()) {
            1 -> RdpException.ConnectionFailed()
            2 -> RdpException.AuthenticationFailed()
            3 -> RdpException.ProtocolException()
            4 -> RdpException.TlsException()
            5 -> RdpException.Disconnected()
            6 -> RdpException.IoException()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: RdpException): ULong {
        return when(value) {
            is RdpException.ConnectionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is RdpException.AuthenticationFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is RdpException.ProtocolException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is RdpException.TlsException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is RdpException.Disconnected -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is RdpException.IoException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: RdpException, buf: ByteBuffer) {
        when(value) {
            is RdpException.ConnectionFailed -> {
                buf.putInt(1)
                Unit
            }
            is RdpException.AuthenticationFailed -> {
                buf.putInt(2)
                Unit
            }
            is RdpException.ProtocolException -> {
                buf.putInt(3)
                Unit
            }
            is RdpException.TlsException -> {
                buf.putInt(4)
                Unit
            }
            is RdpException.Disconnected -> {
                buf.putInt(5)
                Unit
            }
            is RdpException.IoException -> {
                buf.putInt(6)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




